#include &lt;iostream&gt;
using namespace std;

template&lt;class T&gt;
class math &#123;
    private:
        T a;
        T b;
    public:
        math(T a, T b);
        T add();
        T sub();
&#125;;

template&lt;class T&gt;
math&lt;T&gt;::math(T a, T b)&#123;
    this-&gt;a &#x3D; a;
    this-&gt;b &#x3D; b;
&#125;;
template&lt;class T&gt;
T math&lt;T&gt;::add()&#123;
    return a + b;
&#125;;
template&lt;class T&gt;
T math&lt;T&gt;::sub()&#123;
    return a - b;
&#125;;

int main(int argc, const char * argv[]) &#123;
    math&lt;int&gt; m1(10,5);
    math&lt;float&gt; m2(2.5,0.5);
    cout &lt;&lt; m1.add() &lt;&lt; endl &lt;&lt; m1.sub() &lt;&lt; endl;
    cout &lt;&lt; m2.add() &lt;&lt; endl &lt;&lt; m2.sub() &lt;&lt; endl;
    return 0;
&#125;

int power(int m, int n)&#123;
   if(n==0)
       return 1;
   else
       return power(m, n-1)*m;
&#125;

int main(int argc, const char * argv[]) &#123;
    printf("%d\n", power(2, 5));
    return 0;
&#125;


Faster solutionint power(int m, int n)&#123;
    if(n==0)
        return 1;
    if(n%2==0)
        return power(m*m, n/2);
    else
        return m*power(m*m, (n-1)/2);
&#125;

int main(int argc, const char * argv[]) &#123;
    printf("%d\n", power(2, 5));
    return 0;
&#125;

#include &lt;stdio.h>

int factorial(int n)&#123;
    if (n==0) &#123;
        return 1;
    &#125; else &#123;
        return factorial(n-1)*n;
    &#125;
&#125;

int main(int argc, const char * argv[]) &#123;
    int num = 5;
    printf("%d\n", factorial(num));
    return 0;
&#125;

#include &lt;stdio.h>

int sum(int n)&#123;
    if (n==0) &#123;
        return 0;
    &#125; else &#123;
        return sum(n-1)+n;
    &#125;
&#125;

int main(int argc, const char * argv[]) &#123;
    int num = 5;
    printf("%d ", sum(num));
    return 0;
&#125;

什麼是component?
元件(component)是一段獨立的程式碼，代表網頁的一部份。元件有自己的資料與Javascript，通常也帶有自己的樣式。可以包含其他的元件，也能彼此進行溝通。元件可以是按鈕或是圖示，也可以是能在整個網站或網頁中重複使用的表單這種大元素。

元件基礎撰寫一個間單的元件
const SimpleButton = &#123;
    template: &lt;button>Simple button&lt;/button>
&#125;
接下來可以透過 components物件將這個元件傳進app中
&lt;script src="https://cdn.jsdelivr.net/npm/vue@2.6.14/dist/vue.js">&lt;/script>
&lt;div id="app">
    &lt;simple-button>&lt;/simple-button>
&lt;/div>
&lt;script>
    const SimpleButton = &#123;
        template: '&lt;button>Simple Button&lt;/button>'
    &#125;;
    new Vue(&#123;
        el: '#app',
        components: &#123;
            SimpleButton
        &#125;
    &#125;);
&lt;/script>

也可以透過全域的方式註冊元件
Vue.component('simple-button', &#123;
    template: 'button>Simple Button&lt;/button>'
&#125;)

No.9 Palindrome Number





Problem
Given an integer x, return true if x is palindrome integer.
An integer is a palindrome when it reads the same backward as forward. For example, 121 is palindrome while 123 is not.

簡單來說，題目給定整數x，只要順著與反著順序相同回傳True反之Fasle。
解題思路在做任何題目之前，千萬別著急開始coding，應當先理清題目與假設會遇到的情況，將解題流程拆分成數個條件，再來寫程式與測試。

條件一 x 不能為負 

正反順序相同，前面若是配上個-負號就不能通過，所以x &lt;  0則return false


條件二 頭尾需相同

正反順序相同，意味著頭與尾是同個數字，所以檢測頭尾是否相同，不同則return false


條件三 須符合鏡射

正反順序相同，也就代表以該數中間為中心，左右數字需對稱，所以若不符合鏡射則return false



my solution/**
 * @param &#123;number&#125; x
 * @return &#123;boolean&#125;
 */
var isPalindrome = function(x) &#123;
  const array = x.toString();
  const len = array.length;
  if(x &lt; 0 || array[0] !== array[len-1]) 
    return false
  else &#123;
    for(let i = 1; i &lt; (len-1) / 2 + 1; i++) 
      if(array[i-1] !== array[Math.abs(i-len)]) 
        return false
    return true
  &#125;
&#125;;

